{
  "sentences": [
    {
      "text": "這個衣服有瑕疵，我可以退貨嗎？",
      "pinyin": "Zhège yīfu yǒu xiácī, wǒ kěyǐ tuìhuò ma?",
      "pinyin_numeric": "zhe4 ge5 yi1 fu5 you3 xia2 ci1, wo3 ke3 yi3 tui4 huo4 ma0",
      "translation_en": "This clothing has a defect; can I return it?",
      "translation_ko": "이 옷에 하자가 있는데, 환불할 수 있나요?"
    },
    {
      "text": "這雙鞋子尺寸不合，可以換貨嗎？",
      "pinyin": "Zhè shuāng xiézi chǐcùn bù hé, kěyǐ huànhuò ma?",
      "pinyin_numeric": "zhe4 shuang1 xie2 zi5 chi3 cun4 bu4 he2, ke3 yi3 huan4 huo4 ma0",
      "translation_en": "These shoes don't fit; can I exchange them?",
      "translation_numeric": "These shoes are the wrong size; can I exchange them?",
      "translation_ko": "이 신발 사이즈가 안 맞는데, 교환할 수 있나요?"
    },
    {
      "text": "我買的包包顏色不對，可以退貨嗎？",
      "pinyin": "Wǒ mǎi de bāobāo yánsè bù duì, kěyǐ tuìhuò ma?",
      "pinyin_numeric": "wo3 mai3 de5 bao1 bao1 yan2 se4 bu4 dui4, ke3 yi3 tui4 huo4 ma0",
      "translation_en": "The bag I bought is the wrong color; can I return it?",
      "translation_ko": "제가 산 가방 색상이 다른데, 환불할 수 있나요?"
    },
    {
      "text": "這件外套破掉了，可以換貨嗎？",
      "pinyin": "Zhè jiàn wàitào pò diào le, kěyǐ huànhuò ma?",
      "pinyin_numeric": "zhe4 jian4 wai4 tao4 po4 diao4 le5, ke3 yi3 huan4 huo4 ma0",
      "translation_en": "This jacket is torn; can I exchange it?",
      "translation_ko": "이 외투가 찢어졌는데, 교환할 수 있나요?"
    },
    {
      "text": "我買的書髒掉了，可以退貨嗎？",
      "pinyin": "Wǒ mǎi de shū zāng diào le, kěyǐ tuìhuò ma?",
      "pinyin_numeric": "wo3 mai3 de5 shu1 zang1 diao4 le5, ke3 yi3 tui4 huo4 ma0",
      "translation_en": "The book I bought is dirty; can I return it?",
      "translation_ko": "제가 산 책이 더러워졌는데, 환불할 수 있나요?"
    },
    {
      "text": "這個手機壞掉了，可以換貨嗎？",
      "pinyin": "Zhège shǒujī huài diào le, kěyǐ huànhuò ma?",
      "pinyin_numeric": "zhe4 ge5 shou3 ji1 huai4 diao4 le5, ke3 yi3 huan4 huo4 ma0",
      "translation_en": "This phone is broken; can I exchange it?",
      "translation_ko": "이 핸드폰이 고장 났는데, 교환할 수 있나요?"
    },
    {
      "text": "我買的褲子尺寸不合，可以退貨嗎？",
      "pinyin": "Wǒ mǎi de kùzi chǐcùn bù hé, kěyǐ tuìhuò ma?",
      "pinyin_numeric": "wo3 mai3 de5 ku4 zi5 chi3 cun4 bu4 he2, ke3 yi3 tui4 huo4 ma0",
      "translation_en": "The pants I bought don't fit; can I return them?",
      "translation_ko": "제가 산 바지 사이즈가 안 맞는데, 환불할 수 있나요?"
    },
    {
      "text": "這個杯子破掉了，可以換貨嗎？",
      "pinyin": "Zhège bēizi pò diào le, kěyǐ huànhuò ma?",
      "pinyin_numeric": "zhe4 ge5 bei1 zi5 po4 diao4 le5, ke3 yi3 huan4 huo4 ma0",
      "translation_en": "This cup is broken; can I exchange it?",
      "translation_ko": "이 컵이 깨졌는데, 교환할 수 있나요?"
    },
    {
      "text": "我買的帽子顏色不對，可以退貨嗎？",
      "pinyin": "Wǒ mǎi de màozi yánsè bù duì, kěyǐ tuìhuò ma?",
      "pinyin_numeric": "wo3 mai3 de5 mao4 zi5 yan2 se4 bu4 dui4, ke3 yi3 tui4 huo4 ma0",
      "translation_en": "The hat I bought is the wrong color; can I return it?",
      "translation_ko": "제가 산 모자 색상이 다른데, 환불할 수 있나요?"
    },
    {
      "text": "這個包包有瑕疵，可以換貨嗎？",
      "pinyin": "Zhège bāobāo yǒu xiácī, kěyǐ huànhuò ma?",
      "pinyin_numeric": "zhe4 ge5 bao1 bao1 you3 xia2 ci1, ke3 yi3 huan4 huo4 ma0",
      "translation_en": "This bag has a defect; can I exchange it?",
      "translation_ko": "이 가방에 하자가 있는데, 교환할 수 있나요?"
    }
  ]
}
